using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Meta.Application.Meta;
namespace Games.Meta.Discord;
public sealed class MetaDiscordHandler(IMetaService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"profile","season","metatop","achievements","streaks");public async Task HandleAsync(DiscordMessageContext c){var cmd=DiscordCommand.Parts(c)[0].ToLowerInvariant();var scope=DiscordCommand.ScopeId(c);var uid=DiscordCommand.UserId(c);object r=cmd switch{"season"=>await service.GetActiveSeasonAsync(c.CancellationToken),"metatop"=>await service.GetTopAsync(scope,10,c.CancellationToken),"achievements"=>await service.GetAchievementsAsync(scope,uid,c.CancellationToken),"streaks"=>await service.GetGameStreaksAsync(scope,uid,c.CancellationToken),_=>await service.GetProfileAsync(scope,uid,DiscordCommand.DisplayName(c),c.CancellationToken)};await DiscordCommand.ReplyResultAsync(c,r,"Meta");}}
public static class MetaDiscordModule{public static IServiceCollection AddMetaDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,MetaDiscordHandler>();}
